--
-- Table structure for table `image_detection_data`
--

DROP TABLE IF EXISTS `image_detection_data`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `image_detection_data` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `model_id` int DEFAULT NULL COMMENT '使用的模型ID，关联model_management表的model_id字段',
  `detected_images_count` int DEFAULT '0' COMMENT '检测图片数量',
  `bsgxx_count` int DEFAULT '0' COMMENT '正常目标数量',
  `bsgzx_count` int DEFAULT '0' COMMENT '维修目标数量',
  `bsggh_count` int DEFAULT '0' COMMENT '更换目标数量',
  `miss_detection_rate` decimal(5,2) DEFAULT '0.00' COMMENT '图片漏检率',
  `start_time` datetime DEFAULT NULL COMMENT '检测开始时间',
  `finished_at` datetime DEFAULT NULL COMMENT '检测完成时间',
  `folder_path` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '上传图片路径',
  `result_path` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '检测结果保存路径',
  `annotated_images_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '带标注框的图片文件夹路径',
  `detection_instances_count` int DEFAULT '0' COMMENT '检测结果实例数量',
  PRIMARY KEY (`id`),
  KEY `idx_model_id` (`model_id`),
  CONSTRAINT `fk_image_detection_model` FOREIGN KEY (`model_id`) REFERENCES `model_management` (`model_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=354 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='图像检测数据表';
/*!40101 SET character_set_client = @saved_cs_client */;

